// invertmatrix01: October 15, 2025
// Given an NxN matrix, find its inverse, or report the matrix as singular.
int invertmatrix01(const vector <vector <double>> &inmat, int N, vector <vector <double>> &outmat, int verbose)
{
  vector <vector <double>> solvemat;
  vector <double> xvec;
  long i,j,k,status;
  i=j=k=status=0;
  
  make_dmat(N,N+1,solvemat);
  make_dmat(N,N,outmat);

  for(k=0;k<N;k++) {
    // Solve for the kth column of the output matrix
    for(i=0;i<N;i++) {
      solvemat[i][0] = 0.0;
      for(j=0;j<N;j++) solvemat[i][1+j] = inmat[i][j];
    }
    solvemat[k][0] = -1.0;
    xvec={};
    make_dvec(N,xvec);
    status = solvematrix01(solvemat, N, xvec, verbose);
    if(verbose>1) cout << "solvematrix finished OK, xvec = " << xvec[0] << " " << xvec[1] << "\n";
    if(status!=0) {
      cerr << "ERROR: solvematrix01, called from invertmatrix01, returns error code " << status << "\n";
      return(status);
    }
    for(i=0;i<N;i++) outmat[i][k] = xvec[i];
  }
  return(0);
}


// perfectpoly01: November 23, 2021:
// Given a y-vector and an x-vector with the same number N of points,
// calculate the coefficients of a polynomial function y=f(x), of order
// N-1, that precisely passes through all the points.
int perfectpoly01(const vector <double> &x, const vector <double> &y, vector <double> &fitvec)
{
  vector <vector <double>> dmatrix;
  vector <double> outvec;
  unsigned int i=0;
  unsigned int j=0;
  unsigned int k=0;
  int status=0;
  unsigned int npoints = x.size();
  if(y.size() != npoints) {
    cerr << "ERROR: x and y vectors in perfectpoly don't have the same number of points!\n";
    return(1);
  }
  if(npoints<=1) {
    cerr << "ERROR: perfectpoly cannot fit just a single point!\n";
    return(2);
  }
  make_dmat(npoints,npoints+1,dmatrix);
  make_dvec(npoints,outvec);
  //cout << "perfectpoly fitting matrix:\n";
  for(i=0;i<npoints;i++) {
    dmatrix[i][0] = -y[i];
    //cout << dmatrix[i][0] << " ";
    for(j=1;j<=npoints;j++) {
      dmatrix[i][j] = 1.0;
      for(k=2;k<=j;k++) dmatrix[i][j]*=x[i];
      //cout << dmatrix[i][j] << " ";
    }
    //cout << "\n";
  }
  status=solvematrix01(dmatrix,npoints,fitvec,0);
  return(status);
}

